import streamlit as ast
ast.header("My dream astronomy🌠")
ast.title("✨ระบบสุริยะ")
ast.write("องค์ประกอบหลักของระบบสุริยะ  \nดวงอาทิตย์ (The Sun): เป็นดาวฤกษ์ศูนย์กลางที่มีมวลมากที่สุด คิดเป็น 99.8% ของมวลทั้งหมดในระบบสุริยะ ทำหน้าที่เป็นแหล่งพลังงานความร้อนและแสงสว่าง")
ast.write("ดาวเคราะห์ชั้นใน (Inner Planets): หรือดาวเคราะห์หิน เป็นดาวเคราะห์ที่อยู่ใกล้ดวงอาทิตย์ มีพื้นผิวเป็นของแข็ง ได้แก่ ดาวพุธ (Mercury), ดาวศุกร์ (Venus), โลก (Earth), และดาวอังคาร (Mars) ")
ast.write("ดาวเคราะห์ชั้นนอก (Outer Planets): หรือดาวเคราะห์แก๊สและน้ำแข็ง เป็นดาวเคราะห์ขนาดใหญ่ที่อยู่ถัดออกไป ได้แก่ ดาวพฤหัสบดี (Jupiter), ดาวเสาร์ (Saturn), ดาวยูเรนัส (Uranus), และดาวเนปจูน (Neptune)")
ast.write("วัตถุขนาดเล็กอื่น ๆ: ประกอบด้วยดาวเคราะห์แคระ (เช่น ดาวพลูโต), ดาวเคราะห์น้อย (Asteroids), วัตถุในแถบไคเปอร์, ดาวหาง (Comets), และกลุ่มฝุ่นก๊าซ")
ast.image("solarsystem.jpg", caption="รูปภาพระบบสุริยะ")
ast.write("☀️ ดาวฤกษ์ศูนย์กลาง (The Sun)ดวงอาทิตย์ (The Sun): เป็นดาวฤกษ์ชนิดสเปกตรัม G2V มีอายุประมาณ 4,600 ล้านปี พื้นผิวภายนอกมีอุณหภูมิสูงราว 5,500 องศาเซลเซียส ส่วนที่ใจกลางสูงถึง 15 ล้านองศาเซลเซียส พลังงานทั้งหมดเกิดจากปฏิกิริยานิวเคลียร์ฟิวชันที่เปลี่ยนไฮโดรเจนเป็นฮีเลียม ส่งผลให้มีแสงสว่างและพลังงานค้ำจุนสิ่งมีชีวิตบนโลก")
ast.write('🪨 ดาวเคราะห์ชั้นใน (ดาวเคราะห์หิน)เป็นดาวเคราะห์ที่มีพื้นผิวเป็นของแข็ง ประกอบด้วยหินและโลหะ มีขนาดเล็กและไม่มีระบบวงแหวนดาวพุธ (Mercury): ดาวเคราะห์ที่อยู่ใกล้ดวงอาทิตย์ที่สุดและมีขนาดเล็กที่สุด ไม่มีชั้นบรรยากาศคอยดักจับความร้อน ทำให้ด้านที่หันเข้าหาดวงอาทิตย์ร้อนจัด (สูงถึง 430°C) และด้านตรงข้ามเย็นจัด (-180°C) จนได้รับฉายาว่า "เตาไฟแช่แข็ง"')
ast.write('ดาวศุกร์ (Venus): ดาวเคราะห์ที่สว่างที่สุดบนท้องฟ้า (เรียกว่าดาวประกายพรึกหรือดาวประจำเมือง) มีขนาดใกล้เคียงกับโลกจนได้ชื่อว่าเป็น "ฝาแฝดของโลก" แต่มีชั้นบรรยากาศหนาแน่นด้วยก๊าซคาร์บอนไดออกไซด์ เกิดภาวะเรือนกระจกขั้นรุนแรง ทำให้เป็นดาวเคราะห์ที่ร้อนที่สุดในระบบสุริยะ (ประมาณ 465°C) ')
ast.write(" โลก (Earth): ดาวเคราะห์ดวงเดียวในปัจจุบันที่พบสิ่งมีชีวิต มีชั้นบรรยากาศที่เหมาะสม มีน้ำในสถานะของเหลวปกคลุมพื้นผิวถึง 3 ใน 4 ส่วน และมีดวงจันทร์เป็นบริวาร 1 ดวง")
ast.write('ดาวอังคาร (Mars): ดาวเคราะห์สีแดงเนื่องจากพื้นผิวเต็มไปด้วยออกไซด์ของเหล็ก (สนิมเหล็ก) มีชั้นบรรยากาศเบาบาง มีภูเขาไฟ "โอลิมปัส" ซึ่งเป็นภูเขาไฟที่สูงที่สุดในระบบสุริยะ และมีดวงจันทร์บริวารเล็ก ๆ 2 ดวง (โฟบอสและดีมอส) ')
ast.write(' 🌌 ดาวเคราะห์ชั้นนอก (ดาวเคราะห์แก๊สและน้ำแข็ง)เป็นดาวเคราะห์ขนาดใหญ่ที่อยู่ห่างออกไป ไม่มีพื้นผิวที่เป็นของแข็งชัดเจน แต่เต็มไปด้วยแก๊สและของเหลวหนาแน่น และทุกดวงมีระบบวงแหวนดาวพฤหัสบดี (Jupiter): ดาวเคราะห์ที่ใหญ่ที่สุดในระบบสุริยะ (มวลมากกว่าดาวเคราะห์ดวงอื่นรวมกันถึง 2.5 เท่า) หมุนรอบตัวเองเร็วที่สุด โครงสร้างหลักเป็นแก๊สไฮโดรเจนและฮีเลียม จุดเด่นคือ "จุดแดงใหญ่" (Great Red Spot) ซึ่งเป็นพายุหมุนขนาดใหญ่ที่มีอายุหลายร้อยปี และมีดวงจันทร์บริวารจำนวนมาก')
